const crypto = require('crypto');
const express = require('express');

// IMPORTANT: Use express.raw() for webhook — not express.json()
app.post('/api/webhook/razorpay', express.raw({ type: 'application/json' }), async (req, res) => {
  const signature = req.headers['x-razorpay-signature'];
  const secret = process.env.RAZORPAY_WEBHOOK_SECRET;

  // Verify webhook signature
  const expectedSig = crypto
    .createHmac('sha256', secret)
    .update(req.body)
    .digest('hex');

  if (expectedSig !== signature) {
    return res.status(400).json({ error: 'Invalid signature' });
  }

  const event = JSON.parse(req.body.toString());

  switch (event.event) {
    case 'payment.captured':
      const payment = event.payload.payment.entity;
      await db.query(
        'UPDATE orders SET status=$1, payment_id=$2 WHERE razorpay_order_id=$3',
        ['paid', payment.id, payment.order_id]
      );
      break;

    case 'payment.failed':
      await db.query(
        'UPDATE orders SET status=$1 WHERE razorpay_order_id=$2',
        ['payment_failed', event.payload.payment.entity.order_id]
      );
      break;

    case 'refund.processed':
      await db.query(
        'UPDATE orders SET status=$1 WHERE payment_id=$2',
        ['refunded', event.payload.refund.entity.payment_id]
      );
      break;
  }

  res.json({ status: 'ok' });
});

