void filter_odd(int arr[], int n) 
{ 
    int i, k; 
    k = 0; 

    // Traversing the given array  
    // from first to last 
    for (i = 0; i < n; i++) { 

        // If arr[i] is even then 
        // store it at current index 
        if (arr[i] % 2 == 0) { 
            arr[k++] = arr[i]; 
        } 
    } 

    // Modifying original array 
    // elements afterkth index 
    while (k < n) { 
        arr[k++] = 0; 
    } 

    // Print the array elements 
    std::cout << "Modified array is : "; 
    for (i = 0; i < n; i++) { 
        std::cout << arr[i] << " "; 
    } 
} 

