public class loancalculator extends Activity {

    EditText loanamount, interestrate, repaymentperiod;
    TextView txtmonthlypayments;
    Button calculate;
    Double ans;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.loancalculator);

        loanamount=(EditText)findViewById(R.id.loanamount);
        interestrate=(EditText)findViewById(R.id.interestrate);
        repaymentperiod= (EditText)findViewById(R.id.paymentperiod);
        txtmonthlypayments=(TextView) findViewById(R.id.result);
        calculate=(Button) findsViewById(R.id.calculate);
        calculate.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                double p = Double.parseDouble(loanamount.getText().toString());
                double r = Double.parseDouble(interestrate.getText().toString());
                double n = Double.parseDouble(repaymentperiod.getText().toString());
                double numerator;
                double denominator;
                double rate;
                double interest;
                numerator = p * (r/1200);
                denominator = 1 - Math.pow((1 + (r/1200)),(-1*n));
                rate  = numerator / denominator;
