def longest_consecutive(string):
    character_list = []
    max_length = 0
    max_sequence = ''
    for char in string:
        if char in character_list:
            continue
        else:
            character_list.append(char)
            current_length = 1
            for i in range(1, len(string)):
                if string[i-1] == char and string[i] == char:
                    current_length += 1
            if current_length>max_length:
                max_length = current_length
