// Create order (call this before showing payment UI)
async function createOrder(amount, currency = 'INR', receipt) {
  const order = await razorpay.orders.create({
    amount: amount * 100,  // Razorpay uses paise (1 INR = 100 paise)
    currency,
    receipt,
    notes: { source: 'webapp' },
  });
  return order;
}

// Verify payment signature (call this after payment success callback)
function verifyPayment(orderId, paymentId, signature) {
  const body = orderId + '|' + paymentId;
  const expectedSignature = crypto
    .createHmac('sha256', process.env.RAZORPAY_KEY_SECRET)
    .update(body)
    .digest('hex');
  return expectedSignature === signature;
}

