def search_BST(root, key): 

    # Base Condition 
    if root is None or root.val == key: 
        return root 

    # If key is greater than root's key 
    if root.val < key: 
        return search_BST(root.right, key) 

    # If key is smaller than root's key 
    return search_BST(root.left, key) 

