def evaluate(root):
    # empty tree
    if root is None:
        return 0
    # leaf node
    if root.left is None and root.right is None:
        return int(root.data)
    # evaluate left tree
    left_sum = evaluate(root.left)

    # evaluate right tree
    right_sum = evaluate(root.right)

    # check which operation to apply
    if root.data == '+':
        return left_sum + right_sum

    elif root.data == '-':
        return left_sum - right_sum

    elif root.data == '*':
        return left_sum * right_sum

    else:
        return left_sum / right_sum

