char* encrypt(const char *str) 
{ 
    int len = strlen(str); 

    // Create an output string of size twice 
    char *encryption_str = (char*)malloc(2*len); 

    // Store encryption in output string 
    int j=0; 
    for (int i=0; i<len; i++, j++) 
    { 
        encryption_str[j] = (str[i] + 3) % 26; 
        j++; 
        encryption_str[j] = (str[i] + 5) % 26; 
    } 

    // Return the resultant string 
    return encryption_str; 
} 

