function maxFrequencyChar(str) {
  let maxChar = '';
  let maxFrequency = 0;
  let hashTable = {};

  for(let char of str) {
    if (hashTable[char]) {
      hashTable[char] += 1;
    } else {
      hashTable[char] = 1;
    }
  }

  for(let char in hashTable) {
    if(hashTable[char] > maxFrequency) {
      maxFrequency = hashTable[char];
      maxChar = char;
    }
  }

  return maxChar;
}

