function findCommonNumbers(arrA, arrB, arrC) { 
  let common = []; 

  for (let i=0; i < arrA.length; i++) { 
    if (arrB.includes(arrA[i]) && arrC.includes(arrA[i])) { 
      common.push(arrA[i]); 
    } 
    if (common.length === 3) { 
      break; 
    } 
  } 
  return common; 
} 

